import{_ as r,o as t,c as o,a3 as a}from"./chunks/framework.LBeL10WQ.js";const m=JSON.parse('{"title":"Discover getinside - Retail Media Platform","description":"Discover how getinside monetizes your parcels and emails while funding your acquisition. The retail media platform for advertisers and e-retailers.","frontmatter":{"title":"Discover getinside - Retail Media Platform","description":"Discover how getinside monetizes your parcels and emails while funding your acquisition. The retail media platform for advertisers and e-retailers.","keywords":["retail media","monetization","parcels","email marketing","e-commerce","advertising platform","getinside"],"image":"/images/gi-keyvisual.svg"},"headers":[],"relativePath":"en/start-here/index.md","filePath":"en/start-here/index.md"}'),i={name:"en/start-here/index.md"};function n(s,e,l,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="transform-your-audiences-into-revenue" tabindex="-1">Transform your audiences into revenue <a class="header-anchor" href="#transform-your-audiences-into-revenue" aria-label="Permalink to &quot;Transform your audiences into revenue&quot;">​</a></h1><p>Join <strong>+250 e-retailers</strong> and <strong>+300 advertisers</strong> who use getinside to directly monetize their audiences. <strong>+950 campaigns</strong> successfully operated.</p><hr><h2 id="the-4-pillars-of-getinside" tabindex="-1">The 4 Pillars of getinside <a class="header-anchor" href="#the-4-pillars-of-getinside" aria-label="Permalink to &quot;The 4 Pillars of getinside&quot;">​</a></h2><h3 id="🎯-for-advertisers-performance-trust" tabindex="-1">🎯 For Advertisers: Performance &amp; Trust <a class="header-anchor" href="#🎯-for-advertisers-performance-trust" aria-label="Permalink to &quot;🎯 For Advertisers: Performance &amp; Trust&quot;">​</a></h3><p><strong>100% open rate</strong> on parcel inserts thanks to the hyper-attention of unboxing. <strong>1-10% CTR</strong> and <strong>10-30% post-scan conversion</strong> — the highest performance on the market.</p><p>Diversify your acquisition channels against Google and Meta saturation. Benefit from the trust (Endorsement) of the e-retailer towards its community.</p><p><a href="/handbook/en/advertisers/">Go to the Advertiser Portal →</a></p><hr><h3 id="📦-for-retailers-revenue-control" tabindex="-1">📦 For Retailers: Revenue &amp; Control <a class="header-anchor" href="#📦-for-retailers-revenue-control" aria-label="Permalink to &quot;📦 For Retailers: Revenue &amp; Control&quot;">​</a></h3><p><strong>+2% to +20% additional turnover</strong> composed almost entirely of <strong>65-70% net margin</strong>.</p><p>Generate revenue effortlessly while keeping absolute control over the brands you agree to broadcast to your customers. No heavy technical integration.</p><p><a href="/handbook/en/publishers/">Go to the Retailer Portal →</a></p><hr><h3 id="🔄-the-smart-funding-model-virtuous-circle" tabindex="-1">🔄 The Smart Funding Model: Virtuous Circle <a class="header-anchor" href="#🔄-the-smart-funding-model-virtuous-circle" aria-label="Permalink to &quot;🔄 The Smart Funding Model: Virtuous Circle&quot;">​</a></h3><p>Transform your <strong>cost centers</strong> (parcels, emails) into <strong>profit centers</strong>, and immediately reinvest the earnings to fund your own customer acquisition <strong>without spending cash</strong>.</p><p><strong>3 steps:</strong></p><ol><li><strong>Earn</strong>: Monetize your parcels and emails</li><li><strong>Fund</strong>: Use this balance (Wallet) immediately</li><li><strong>Grow</strong>: Buy qualified traffic for your own site</li></ol><hr><h3 id="🛡️-the-trusted-third-party-one-contract-completely-secure" tabindex="-1">🛡️ The Trusted Third Party: One Contract, Completely Secure <a class="header-anchor" href="#🛡️-the-trusted-third-party-one-contract-completely-secure" aria-label="Permalink to &quot;🛡️ The Trusted Third Party: One Contract, Completely Secure&quot;">​</a></h3><p>A single contract, a single billing, and guaranteed, secure payments.</p><p>getinside centralizes the entire ecosystem: tech integration, printing, routing, tracking, GDPR. <strong>No more complex management.</strong></p><hr><div class="info custom-block"><p class="custom-block-title">Ready to start?</p><ul><li><strong>Advertiser</strong>: Reach your future customers via highly qualified audiences</li><li><strong>Retailer</strong>: Transform your parcels into additional revenue</li></ul><p><a href="mailto:studio@getinside.com" target="_blank" rel="noreferrer">Discuss my project →</a></p></div>',24)])])}const g=r(i,[["render",n]]);export{m as __pageData,g as default};
